296	async function invokeModelMaxImagesPerCall(model: ImageModelV3) {
297	  const isFunction = model.maxImagesPerCall instanceof Function;
298	
299	  if (!isFunction) {
300	    return model.maxImagesPerCall;
301	  }
302	
303	  return model.maxImagesPerCall({
304	    modelId: model.modelId,
305	  });
306	}
307	
308	function normalizePrompt(
309	  prompt: GenerateImagePrompt,
310	): Pick<ImageModelV3CallOptions, 'prompt' | 'files' | 'mask'> {
311	  if (typeof prompt === 'string') {
312	    return { prompt, files: undefined, mask: undefined };
313	  }
314	
315	  return {
316	    prompt: prompt.text,
317	    files: prompt.images.map(toImageModelV3File),
318	    mask: prompt.mask ? toImageModelV3File(prompt.mask) : undefined,
319	  };
320	}
321	
322	function toImageModelV3File(dataContent: DataContent): ImageModelV3File {
323	  if (typeof dataContent === 'string' && dataContent.startsWith('http')) {
324	    return {
325	      type: 'url',
326	      url: dataContent,
327	    };
328	  }
329	
330	  // Handle data URLs
331	  if (typeof dataContent === 'string' && dataContent.startsWith('data:')) {
332	    const { mediaType: dataUrlMediaType, base64Content } =
333	      splitDataUrl(dataContent);
334	
335	    if (base64Content != null) {
336	      const uint8Data = convertBase64ToUint8Array(base64Content);
337	      return {
338	        type: 'file',
339	        data: uint8Data,
340	        mediaType:
341	          dataUrlMediaType ||
342	          detectMediaType({
343	            data: uint8Data,
344	            signatures: imageMediaTypeSignatures,
345	          }) ||
346	          'image/png',
347	      };
348	    }
349	  }
350	
351	  const uint8Data = convertDataContentToUint8Array(dataContent);
352	  return {
353	    type: 'file',
354	    data: uint8Data,
355	    mediaType:
356	      detectMediaType({
357	        data: uint8Data,
358	        signatures: imageMediaTypeSignatures,
359	      }) || 'image/png',
360	  };
361	}
