      failedResponseHandler: openaiFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(openaiImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch
    });

    return {
      images: response.data.map(item => item.b64_json),  // Base64 encoded
      warnings,
      usage: { inputTokens, outputTokens, totalTokens },
      response: { timestamp, modelId, headers },
      providerMetadata: {
        openai: {
          images: response.data.map(item => ({
            revisedPrompt,
            created,
            size,
            quality,
            background,
            outputFormat,
            imageTokens,
            textTokens
          }))
        }
      }
    };
  }
}
```

**Key Implementation Details:**
- Implements `ImageModelV3` interface from `@ai-sdk/provider`
- Handles both generation and editing (with files)
- Returns base64-encoded images
- Includes detailed metadata (revised prompts, token usage, etc.)
