export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: OpenAIImageModelId,
    private readonly config: OpenAIImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0]
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    // Handle image editing with files
    if (files != null) {
      const response = await postFormDataToApi({
        url: '/images/edits',
        headers: combineHeaders(this.config.headers(), headers),
        formData: convertToFormData({
          model: this.modelId,
          prompt,
          image: /* convert files to blobs */,
          mask: /* convert mask to blob */,
          n, size,
          ...providerOptions.openai
        }),
        failedResponseHandler: openaiFailedResponseHandler,
        successfulResponseHandler: createJsonResponseHandler(openaiImageResponseSchema),
        abortSignal,
        fetch: this.config.fetch
      });
      return { images, warnings, usage, response, providerMetadata };
    }

    // Handle standard image generation
    const response = await postJsonToApi({
      url: '/images/generations',
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n, size,
        ...providerOptions.openai,
        ...(!hasDefaultResponseFormat(this.modelId)
          ? { response_format: 'b64_json' }
          : {}),
      },
      failedResponseHandler: openaiFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(openaiImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch
    });

    return {
      images: response.data.map(item => item.b64_json),  // Base64 encoded
      warnings,
      usage: { inputTokens, outputTokens, totalTokens },
      response: { timestamp, modelId, headers },
      providerMetadata: {
        openai: {
          images: response.data.map(item => ({
            revisedPrompt,
            created,
            size,
            quality,
            background,
            outputFormat,
            imageTokens,
            textTokens
          }))
        }
      }
    };
  }
}
```

