### 4. PROVIDER OPTION SCHEMAS WITH ZOD

**Location**: `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775507127718-o7bx01/packages/luma/src/luma-image-model.ts`

#### Schema Definition Pattern:
```typescript
import { InferSchema, lazySchema, zodSchema } from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

// Use lazySchema() to defer creation until first use
export const lumaImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      referenceType: z
        .enum(['image', 'style', 'character', 'modify_image'])
        .nullish(),

      images: z
        .array(
          z.object({
            weight: z.number().min(0).max(1).nullish(),
            id: z.string().nullish(),
          }),
        )
        .nullish(),

      pollIntervalMillis: z.number().nullish(),
      maxPollAttempts: z.number().nullish(),
    })
    .passthrough(),  // Allow additional unknown properties
  ),
);

// Type inference from schema
export type LumaImageModelOptions = InferSchema<
  typeof lumaImageModelOptionsSchema
>;
```

#### Using parseProviderOptions:
```typescript
import { parseProviderOptions } from '@ai-sdk/provider-utils';

async doGenerate({ providerOptions, ...rest }: ImageModelV3CallOptions) {
  // Parse and validate provider-specific options
  const lumaOptions = await parseProviderOptions({
    provider: 'luma',  // Must match the key in providerOptions
    providerOptions,
    schema: lumaImageModelOptionsSchema,
  });

  // lumaOptions is now typed as LumaImageModelOptions | undefined
  const {
    pollIntervalMillis,
    maxPollAttempts,
    referenceType,
    images: imageConfigs,
  } = lumaOptions ?? {};
}
```

