### 9. SCHEMA SYSTEM: FLEXIBLE & LAZY

**Location**: `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775507127718-o7bx01/packages/provider-utils/src/schema.ts`

```typescript
// Three schema types supported:
export type FlexibleSchema<SCHEMA = any> =
  | Schema<SCHEMA>                     // Custom schema with Symbol
  | LazySchema<SCHEMA>                // Deferred creation function
  | ZodSchema<SCHEMA>                 // Zod v3 or v4
  | StandardSchema<SCHEMA>;           // Standard Schema interface

// Schema creation helpers:
export function lazySchema<SCHEMA>(
  createSchema: () => Schema<SCHEMA>,
): LazySchema<SCHEMA>  // Defers validator initialization

export function zodSchema<OBJECT>(
  zodSchema: ZodType<OBJECT>,
  options?: { useReferences?: boolean },
): Schema<OBJECT>  // Auto-detects Zod v3 or v4

export type InferSchema<SCHEMA> = 
  // Type inference from schema objects
```

**Why lazySchema()?**
- Reduces startup time
- Avoids initializing unused validators
- Pattern used throughout: `lazySchema(() => zodSchema(z.object(...)))`

