1	import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
2	import {
3	  FetchFunction,
4	  loadApiKey,
5	  withoutTrailingSlash,
6	  withUserAgentSuffix,
7	} from '@ai-sdk/provider-utils';
8	import { LumaImageModel } from './luma-image-model';
9	import { LumaImageModelId } from './luma-image-settings';
10	import { VERSION } from './version';
11	
12	export interface LumaProviderSettings {
13	  /**
14	   * Luma API key. Default value is taken from the `LUMA_API_KEY` environment
15	   * variable.
16	   */
17	  apiKey?: string;
18	  /**
19	   * Base URL for the API calls.
20	   */
21	  baseURL?: string;
22	  /**
23	   * Custom headers to include in the requests.
24	   */
25	  headers?: Record<string, string>;
26	  /**
27	   * Custom fetch implementation. You can use it as a middleware to intercept requests,
28	   * or to provide a custom fetch implementation for e.g. testing.
29	   */
30	  fetch?: FetchFunction;
31	}
32	
33	export interface LumaProvider extends ProviderV3 {
34	  /**
35	   * Creates a model for image generation.
36	   */
37	  image(modelId: LumaImageModelId): ImageModelV3;
38	
39	  /**
40	   * Creates a model for image generation.
41	   */
42	  imageModel(modelId: LumaImageModelId): ImageModelV3;
43	
44	  /**
45	   * @deprecated Use `embeddingModel` instead.
46	   */
47	  textEmbeddingModel(modelId: string): never;
48	}
49	
50	const defaultBaseURL = 'https://api.lumalabs.ai';
51	
52	export function createLuma(options: LumaProviderSettings = {}): LumaProvider {
53	  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
54	  const getHeaders = () =>
55	    withUserAgentSuffix(
56	      {
57	        Authorization: `Bearer ${loadApiKey({
58	          apiKey: options.apiKey,
59	          environmentVariableName: 'LUMA_API_KEY',
60	          description: 'Luma',
61	        })}`,
62	        ...options.headers,
63	      },
64	      `ai-sdk/luma/${VERSION}`,
65	    );
66	
67	  const createImageModel = (modelId: LumaImageModelId) =>
68	    new LumaImageModel(modelId, {
69	      provider: 'luma.image',
70	      baseURL: baseURL ?? defaultBaseURL,
71	      headers: getHeaders,
72	      fetch: options.fetch,
73	    });
74	
75	  const embeddingModel = (modelId: string) => {
76	    throw new NoSuchModelError({
77	      modelId,
78	      modelType: 'embeddingModel',
79	    });
80	  };
81	
82	  return {
83	    specificationVersion: 'v3' as const,
84	    image: createImageModel,
85	    imageModel: createImageModel,
86	    languageModel: (modelId: string) => {
87	      throw new NoSuchModelError({
88	        modelId,
89	        modelType: 'languageModel',
90	      });
91	    },
92	    embeddingModel,
93	    textEmbeddingModel: embeddingModel,
94	  };
95	}
96	
97	export const luma = createLuma();
