7	  createStatusCodeErrorResponseHandler,
8	  FetchFunction,
9	  getFromApi,
10	  parseProviderOptions,
11	  postJsonToApi,
12	} from '@ai-sdk/provider-utils';
13	import { z } from 'zod/v4';
14	import { xaiFailedResponseHandler } from './xai-error';
15	import { xaiImageModelOptions } from './xai-image-options';
16	import { XaiImageModelId } from './xai-image-settings';
