18	interface XaiImageModelConfig {
19	  provider: string;
20	  baseURL: string | undefined;
21	  headers: () => Record<string, string | undefined>;
22	  fetch?: FetchFunction;
23	  _internal?: {
24	    currentDate?: () => Date;
25	  };
26	}
