28	export class XaiImageModel implements ImageModelV3 {
29	  readonly specificationVersion = 'v3';
30	  readonly maxImagesPerCall = 3;
31	
32	  get provider(): string {
33	    return this.config.provider;
34	  }
35	
36	  constructor(
37	    readonly modelId: XaiImageModelId,
38	    private config: XaiImageModelConfig,
39	  ) {}
40	
41	  async doGenerate({
42	    prompt,
43	    n,
44	    size,
45	    aspectRatio,
46	    seed,
47	    providerOptions,
48	    headers,
49	    abortSignal,
50	    files,
51	    mask,
52	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
53	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
54	  > {
55	    const warnings: Array<SharedV3Warning> = [];
56	
57	    if (size != null) {
58	      warnings.push({
59	        type: 'unsupported',
60	        feature: 'size',
61	        details:
62	          'This model does not support the `size` option. Use `aspectRatio` instead.',
63	      });
64	    }
65	
66	    if (seed != null) {
67	      warnings.push({
68	        type: 'unsupported',
69	        feature: 'seed',
70	      });
71	    }
72	
73	    if (mask != null) {
74	      warnings.push({
75	        type: 'unsupported',
76	        feature: 'mask',
77	      });
78	    }
79	
80	    const xaiOptions = await parseProviderOptions({
81	      provider: 'xai',
82	      providerOptions,
83	      schema: xaiImageModelOptions,
84	    });
85	
86	    const hasFiles = files != null && files.length > 0;
87	    const imageUrls = hasFiles
88	      ? files.map(file => convertImageModelFileToDataUri(file))
89	      : [];
90	
91	    const endpoint = hasFiles ? '/images/edits' : '/images/generations';
92	
93	    const body: Record<string, unknown> = {
94	      model: this.modelId,
95	      prompt,
96	      n,
97	      response_format: 'b64_json',
98	    };
99	
100	    if (aspectRatio != null) {
101	      body.aspect_ratio = aspectRatio;
102	    }
103	
104	    if (xaiOptions?.output_format != null) {
105	      body.output_format = xaiOptions.output_format;
106	    }
107	
108	    if (xaiOptions?.sync_mode != null) {
109	      body.sync_mode = xaiOptions.sync_mode;
110	    }
111	
112	    if (xaiOptions?.aspect_ratio != null && aspectRatio == null) {
113	      body.aspect_ratio = xaiOptions.aspect_ratio;
114	    }
115	
116	    if (xaiOptions?.resolution != null) {
117	      body.resolution = xaiOptions.resolution;
118	    }
119	
120	    if (xaiOptions?.quality != null) {
121	      body.quality = xaiOptions.quality;
122	    }
123	
124	    if (xaiOptions?.user != null) {
125	      body.user = xaiOptions.user;
126	    }
127	
128	    if (imageUrls.length === 1) {
129	      body.image = { url: imageUrls[0], type: 'image_url' };
130	    } else if (imageUrls.length > 1) {
131	      body.images = imageUrls.map(url => ({ url, type: 'image_url' }));
132	    }
133	
134	    const baseURL = this.config.baseURL ?? 'https://api.x.ai/v1';
135	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
136	    const { value: response, responseHeaders } = await postJsonToApi({
137	      url: `${baseURL}${endpoint}`,
138	      headers: combineHeaders(this.config.headers(), headers),
139	      body,
140	      failedResponseHandler: xaiFailedResponseHandler,
141	      successfulResponseHandler: createJsonResponseHandler(
142	        xaiImageResponseSchema,
143	      ),
144	      abortSignal,
145	      fetch: this.config.fetch,
146	    });
147	
148	    const hasAllBase64 = response.data.every(image => image.b64_json != null);
149	
150	    const images = hasAllBase64
151	      ? response.data.map(image => image.b64_json!)
152	      : await Promise.all(
153	          response.data.map(image =>
154	            this.downloadImage(image.url!, abortSignal),
155	          ),
156	        );
157	
158	    return {
159	      images,
160	      warnings,
161	      response: {
162	        timestamp: currentDate,
163	        modelId: this.modelId,
164	        headers: responseHeaders,
165	      },
166	      providerMetadata: {
167	        xai: {
168	          images: response.data.map(item => ({
169	            ...(item.revised_prompt
170	              ? { revisedPrompt: item.revised_prompt }
171	              : {}),
172	          })),
173	          ...(response.usage?.cost_in_usd_ticks != null
174	            ? { costInUsdTicks: response.usage.cost_in_usd_ticks }
175	            : {}),
176	        },
177	      },
178	    };
179	  }
180	
181	  private async downloadImage(
182	    url: string,
183	    abortSignal: AbortSignal | undefined,
184	  ): Promise<Uint8Array> {
185	    const { value } = await getFromApi({
186	      url,
187	      abortSignal,
188	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
189	      successfulResponseHandler: createBinaryResponseHandler(),
190	      fetch: this.config.fetch,
191	    });
192	    return value;
193	  }
194	}
195	
196	const xaiImageResponseSchema = z.object({
197	  data: z.array(
198	    z.object({
199	      url: z.string().nullish(),
200	      b64_json: z.string().nullish(),
201	      revised_prompt: z.string().nullish(),
202	    }),
203	  ),
204	  usage: z
205	    .object({
206	      cost_in_usd_ticks: z.number().nullish(),
207	    })
208	    .nullish(),
209	});
