  it('should create a provider with specificationVersion v3', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(provider.specificationVersion).toBe('v3');
  });

  it('should create image model via imageModel()', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.imageModel('pixelart-standard');
    expect(model.modelId).toBe('pixelart-standard');
    expect(model.specificationVersion).toBe('v3');
    expect(model.provider).toBe('pixelart.image');
  });

  it('should create image model via image()', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.image('pixelart-hd');
    expect(model.modelId).toBe('pixelart-hd');
  });

  it('should create image model via direct call', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider('pixelart-mini');
    expect(model.modelId).toBe('pixelart-mini');
  });

  it('should use custom provider name', () => {
    const provider = createPixelArt({
      apiKey: 'test-key',
      name: 'custom-pixelart',
    });
    const model = provider.imageModel('pixelart-standard');
    expect(model.provider).toBe('custom-pixelart.image');
  });

  it('should throw for languageModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.languageModel('any-model')).toThrow(
      'PixelArt does not support language models',
    );
  });

  it('should throw for embeddingModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.embeddingModel('any-model')).toThrow(
      'PixelArt does not support embedding models',
    );
  });
});

describe('pixelart', () => {
  it('should be a default instance', () => {
    expect(pixelart.specificationVersion).toBe('v3');
  });
});

