import { describe, it, expect, vi, beforeEach } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_MODEL_ID = 'pixelart-standard';

function createTestConfig(options: {
  response?: object;
  headers?: Record<string, string>;
} = {}) {
  const fetchMock = vi.fn().mockResolvedValue(
    new Response(
      JSON.stringify(
        options.response ?? {
          created: 1234567890,
          data: [{ b64_json: 'dGVzdC1iYXNlNjQtaW1hZ2U=' }],
          usage: {
            input_tokens: 10,
            output_tokens: 20,
            total_tokens: 30,
          },
        },
      ),
      {
        status: 200,
        headers: {
          'Content-Type': 'application/json',
          ...(options.headers ?? {}),
        },
      },
    ),
  );

  return {
    fetchMock,
    config: {
      provider: 'pixelart.image',
      url: ({ path }: { modelId: string; path: string }) =>
        `https://api.pixelart.ai/v1${path}`,
      headers: () => ({
        Authorization: 'Bearer test-api-key',
      }),
      fetch: fetchMock,
      _internal: {
        currentDate: () => new Date('2026-04-06T00:00:00Z'),
      },
    },
  };
}

describe('PixelArtImageModel', () => {
  describe('constructor', () => {
    it('should set modelId', () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);
      expect(model.modelId).toBe(TEST_MODEL_ID);
    });

    it('should set specificationVersion to v3', () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);
      expect(model.specificationVersion).toBe('v3');
    });

    it('should set provider from config', () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);
      expect(model.provider).toBe('pixelart.image');
    });
  });

  describe('maxImagesPerCall', () => {
    it('should return 4 for pixelart-standard', () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel('pixelart-standard', config);
      expect(model.maxImagesPerCall).toBe(4);
    });

    it('should return 2 for pixelart-hd', () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel('pixelart-hd', config);
      expect(model.maxImagesPerCall).toBe(2);
    });

    it('should return 8 for pixelart-mini', () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel('pixelart-mini', config);
      expect(model.maxImagesPerCall).toBe(8);
    });

    it('should return 1 for unknown model', () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel('custom-model', config);
      expect(model.maxImagesPerCall).toBe(1);
    });
  });

  describe('doGenerate', () => {
    it('should send correct request body', async () => {
      const { config, fetchMock } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      await model.doGenerate({
        prompt: 'a cute cat in pixel art',
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: undefined,
      });

      const [url, requestInit] = fetchMock.mock.calls[0];
      expect(url).toBe('https://api.pixelart.ai/v1/images/generations');

      const body = JSON.parse(requestInit.body);
      expect(body.model).toBe(TEST_MODEL_ID);
      expect(body.prompt).toBe('a cute cat in pixel art');
      expect(body.n).toBe(1);
      expect(body.size).toBe('512x512');
      expect(body.response_format).toBe('b64_json');
    });

    it('should return images as base64 strings', async () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      const result = await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: undefined,
      });

      expect(result.images).toEqual(['dGVzdC1iYXNlNjQtaW1hZ2U=']);
    });

    it('should return usage information', async () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      const result = await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: undefined,
      });

      expect(result.usage).toEqual({
        inputTokens: 10,
        outputTokens: 20,
        totalTokens: 30,
      });
    });

    it('should return response metadata', async () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      const result = await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: undefined,
      });

      expect(result.response.modelId).toBe(TEST_MODEL_ID);
      expect(result.response.timestamp).toEqual(
        new Date('2026-04-06T00:00:00Z'),
      );
    });

    it('should warn when aspectRatio is provided', async () => {
      const { config } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      const result = await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: undefined,
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support aspect ratio. Use `size` instead.',
      });
    });

    it('should pass seed when provided', async () => {
      const { config, fetchMock } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 42,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: undefined,
      });

      const body = JSON.parse(fetchMock.mock.calls[0][1].body);
      expect(body.seed).toBe(42);
    });

    it('should pass style provider option', async () => {
      const { config, fetchMock } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {
          pixelart: {
            style: 'retro',
          },
        },
        headers: undefined,
      });

      const body = JSON.parse(fetchMock.mock.calls[0][1].body);
      expect(body.style).toBe('retro');
    });

    it('should pass pixelDensity provider option', async () => {
      const { config, fetchMock } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {
          pixelart: {
            pixelDensity: 8,
          },
        },
        headers: undefined,
      });

      const body = JSON.parse(fetchMock.mock.calls[0][1].body);
      expect(body.pixel_density).toBe(8);
    });

    it('should pass both style and pixelDensity provider options', async () => {
      const { config, fetchMock } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      await model.doGenerate({
        prompt: 'a retro game scene',
        n: 2,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {
          pixelart: {
            style: '8bit',
            pixelDensity: 4,
          },
        },
        headers: undefined,
      });

      const body = JSON.parse(fetchMock.mock.calls[0][1].body);
      expect(body.style).toBe('8bit');
      expect(body.pixel_density).toBe(4);
      expect(body.n).toBe(2);
      expect(body.size).toBe('256x256');
    });

    it('should include authorization header', async () => {
      const { config, fetchMock } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: undefined,
      });

      const requestHeaders = fetchMock.mock.calls[0][1].headers;
      expect(requestHeaders.get('Authorization')).toBe('Bearer test-api-key');
    });

    it('should merge custom headers', async () => {
      const { config, fetchMock } = createTestConfig();
      const model = new PixelArtImageModel(TEST_MODEL_ID, config);

      await model.doGenerate({
        prompt: 'a cute cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: { 'X-Custom': 'test-value' },
      });

      const requestHeaders = fetchMock.mock.calls[0][1].headers;
      expect(requestHeaders.get('X-Custom')).toBe('test-value');
    });
  });
});

